const Redis = require('ioredis');
const { v4: uuidv4 } = require('uuid');

class CouponRedemptionSystem {
  constructor(redisConfig = {}) {
    this.redis = new Redis(redisConfig);
    this.COUPON_PREFIX = 'coupon:';
    this.REDEMPTION_PREFIX = 'redemption:';
    this.USER_REDEMPTION_PREFIX = 'user_redemption:';

    // Register the atomic redemption Lua script
    // This script performs check-and-act atomically within Redis
    this.redeemScript = `
      local couponKey = KEYS[1]
      local redemptionKey = KEYS[2]
      local userRedemptionKey = KEYS[3]

      local userId = ARGV[1]
      local currentTime = tonumber(ARGV[2])
      local redemptionId = ARGV[3]

      -- Check if coupon exists
      local couponData = redis.call('HGETALL', couponKey)
      if #couponData == 0 then
        return cjson.encode({error = 'COUPON_NOT_FOUND', message = 'Coupon does not exist'})
      end

      -- Parse coupon data into a table
      local coupon = {}
      for i = 1, #couponData, 2 do
        coupon[couponData[i]] = couponData[i + 1]
      end

      -- Check if coupon is active
      if coupon['status'] ~= 'active' then
        return cjson.encode({error = 'COUPON_INACTIVE', message = 'Coupon is no longer active'})
      end

      -- Check expiration
      local expiresAt = tonumber(coupon['expiresAt'])
      if expiresAt and currentTime > expiresAt then
        redis.call('HSET', couponKey, 'status', 'expired')
        return cjson.encode({error = 'COUPON_EXPIRED', message = 'Coupon has expired'})
      end

      -- Check start date
      local startsAt = tonumber(coupon['startsAt'])
      if startsAt and currentTime < startsAt then
        return cjson.encode({error = 'COUPON_NOT_STARTED', message = 'Coupon is not yet valid'})
      end

      -- Check max total redemptions
      local maxRedemptions = tonumber(coupon['maxRedemptions'])
      local currentRedemptions = tonumber(coupon['currentRedemptions'] or '0')
      if maxRedemptions and currentRedemptions >= maxRedemptions then
        redis.call('HSET', couponKey, 'status', 'exhausted')
        return cjson.encode({error = 'COUPON_EXHAUSTED', message = 'Coupon has reached maximum redemptions'})
      end

      -- Check per-user redemption limit
      local maxPerUser = tonumber(coupon['maxPerUser'] or '1')
      local userRedemptionCount = tonumber(redis.call('GET', userRedemptionKey) or '0')
      if userRedemptionCount >= maxPerUser then
        return cjson.encode({error = 'USER_ALREADY_REDEEMED', message = 'User has already used this coupon the maximum number of times'})
      end

      -- All checks passed — atomically apply the redemption

      -- Increment coupon redemption count
      local newCount = redis.call('HINCRBY', couponKey, 'currentRedemptions', 1)

      -- If this increment causes us to hit max, mark as exhausted
      if maxRedemptions and newCount >= maxRedemptions then
        redis.call('HSET', couponKey, 'status', 'exhausted')
      end

      -- Increment user-specific redemption count
      redis.call('INCR', userRedemptionKey)
      -- Set TTL on user redemption key to match coupon expiry
      if expiresAt then
        local ttl = expiresAt - currentTime
        if ttl > 0 then
          redis.call('EXPIRE', userRedemptionKey, math.ceil(ttl))
        end
      end

      -- Store redemption record
      local redemptionData = cjson.encode({
        redemptionId = redemptionId,
        couponCode = coupon['code'],
        userId = userId,
        discountType = coupon['discountType'],
        discountValue = coupon['discountValue'],
        redeemedAt = currentTime,
        newRedemptionCount = newCount
      })
      redis.call('SET', redemptionKey, redemptionData)
      -- Keep redemption records for 90 days
      redis.call('EXPIRE', redemptionKey, 7776000)

      return cjson.encode({
        success = true,
        redemptionId = redemptionId,
        discountType = coupon['discountType'],
        discountValue = coupon['discountValue'],
        couponCode = coupon['code'],
        remainingRedemptions = maxRedemptions and (maxRedemptions - newCount) or -1
      })
    `;
  }

  /**
   * Create a new coupon in the system
   */
  async createCoupon({
    code,
    discountType, // 'percentage' or 'fixed'
    discountValue,
    maxRedemptions = null,
    maxPerUser = 1,
    startsAt = null,
    expiresAt = null,
    description = '',
    minOrderAmount = 0,
    maxDiscountAmount = null,
  }) {
    const couponKey = `${this.COUPON_PREFIX}${code.toUpperCase()}`;

    // Check if coupon already exists
    const exists = await this.redis.exists(couponKey);
    if (exists) {
      throw new Error(`Coupon with code "${code}" already exists`);
    }

    if (!['percentage', 'fixed'].includes(discountType)) {
      throw new Error('discountType must be "percentage" or "fixed"');
    }

    if (discountType === 'percentage' && (discountValue <= 0 || discountValue > 100)) {
      throw new Error('Percentage discount must be between 0 and 100');
    }

    if (discountType === 'fixed' && discountValue <= 0) {
      throw new Error('Fixed discount must be greater than 0');
    }

    const couponData = {
      code: code.toUpperCase(),
      discountType,
      discountValue: String(discountValue),
      maxRedemptions: maxRedemptions !== null ? String(maxRedemptions) : '',
      maxPerUser: String(maxPerUser),
      currentRedemptions: '0',
      startsAt: startsAt ? String(new Date(startsAt).getTime()) : '',
      expiresAt: expiresAt ? String(new Date(expiresAt).getTime()) : '',
      status: 'active',
      description,
      minOrderAmount: String(minOrderAmount),
      maxDiscountAmount: maxDiscountAmount !== null ? String(maxDiscountAmount) : '',
      createdAt: String(Date.now()),
    };

    await this.redis.hmset(couponKey, couponData);

    // Set TTL on the coupon key if it has an expiration
    if (expiresAt) {
      const ttlMs = new Date(expiresAt).getTime() - Date.now();
      if (ttlMs > 0) {
        // Add buffer of 24 hours past expiry for record keeping
        await this.redis.pexpire(couponKey, ttlMs + 86400000);
      }
    }

    return { success: true, coupon: couponData };
  }

  /**
   * Redeem a coupon — fully atomic via Lua script.
   * No race condition between check and act.
   */
  async redeemCoupon(couponCode, userId, orderAmount = 0) {
    if (!couponCode || !userId) {
      throw new Error('couponCode and userId are required');
    }

    const normalizedCode = couponCode.toUpperCase().trim();
    const couponKey = `${this.COUPON_PREFIX}${normalizedCode}`;
    const redemptionId = uuidv4();
    const redemptionKey = `${this.REDEMPTION_PREFIX}${redemptionId}`;
    const userRedemptionKey = `${this.USER_REDEMPTION_PREFIX}${normalizedCode}:${userId}`;
    const currentTime = Date.now();

    // Execute the atomic Lua script
    const resultJson = await this.redis.eval(
      this.redeemScript,
      3,
      couponKey,
      redemptionKey,
      userRedemptionKey,
      userId,
      String(currentTime),
      redemptionId
    );

    const result = JSON.parse(resultJson);

    if (result.error) {
      return {
        success: false,
        error: result.error,
        message: result.message,
      };
    }

    // Calculate the actual discount amount (this is deterministic, no race condition here)
    const discountValue = parseFloat(result.discountValue);
    let discountAmount;

    if (result.discountType === 'percentage') {
      discountAmount = (orderAmount * discountValue) / 100;
    } else {
      discountAmount = discountValue;
    }

    // Fetch coupon to check maxDiscountAmount and minOrderAmount
    // These are supplementary checks on the caller side
    const couponData = await this.redis.hgetall(couponKey);

    if (couponData.minOrderAmount && orderAmount < parseFloat(couponData.minOrderAmount)) {
      // Rollback: undo the redemption atomically
      await this.rollbackRedemption(couponKey, redemptionKey, userRedemptionKey);
      return {
        success: false,
        error: 'MIN_ORDER_NOT_MET',
        message: `Minimum order amount of ${couponData.minOrderAmount} not met`,
      };
    }

    if (couponData.maxDiscountAmount && couponData.maxDiscountAmount !== '') {
      const maxDiscount = parseFloat(couponData.maxDiscountAmount);
      if (discountAmount > maxDiscount) {
        discountAmount = maxDiscount;
      }
    }

    // Ensure discount doesn't exceed order amount
    discountAmount = Math.min(discountAmount, orderAmount);
    discountAmount = Math.round(discountAmount * 100) / 100;

    return {
      success: true,
      redemptionId: result.redemptionId,
      couponCode: result.couponCode,
      discountType: result.discountType,
      discountValue,
      discountAmount,
      finalAmount: Math.round((orderAmount - discountAmount) * 100) / 100,
      remainingRedemptions: result.remainingRedemptions,
    };
  }

  /**
   * Atomic rollback of a redemption (used if post-redemption validation fails)
   */
  async rollbackRedemption(couponKey, redemptionKey, userRedemptionKey) {
    const rollbackScript = `
      -- Decrement coupon redemption count
      local newCount = redis.call('HINCRBY', KEYS[1], 'currentRedemptions', -1)
      
      -- If coupon was marked exhausted, reactivate it
      local status = redis.call('HGET', KEYS[1], 'status')
      if status == 'exhausted' then
        redis.call('HSET', KEYS[1], 'status', 'active')
      end
      
      -- Decrement user redemption count
      local userCount = redis.call('DECR', KEYS[3])
      if userCount <= 0 then
        redis.call('DEL', KEYS[3])
      end
      
      -- Remove redemption record
      redis.call('DEL', KEYS[2])
      
      return 1
    `;

    await this.redis.eval(rollbackScript, 3, couponKey, redemptionKey, userRedemptionKey);
  }

  /**
   * Get coupon details (read-only, no race condition concern)
   */
  async getCoupon(couponCode) {
    const normalizedCode = couponCode.toUpperCase().trim();
    const couponKey = `${this.COUPON_PREFIX}${normalizedCode}`;
    const data = await this.redis.hgetall(couponKey);

    if (!data || Object.keys(data).length === 0) {
      return null;
    }

    return {
      ...data,
      discountValue: parseFloat(data.discountValue),
      maxRedemptions: data.maxRedemptions ? parseInt(data.maxRedemptions) : null,
      maxPerUser: parseInt(data.maxPerUser),
      currentRedemptions: parseInt(data.currentRedemptions),
      startsAt: data.startsAt ? new Date(parseInt(data.startsAt)) : null,
      expiresAt: data.expiresAt ? new Date(parseInt(data.expiresAt)) : null,
      minOrderAmount: parseFloat(data.minOrderAmount || '0'),
      maxDiscountAmount: data.maxDiscountAmount ? parseFloat(data.maxDiscountAmount) : null,
    };
  }

  /**
   * Deactivate a coupon
   */
  async deactivateCoupon(couponCode) {
    const normalizedCode = couponCode.toUpperCase().trim();
    const couponKey = `${this.COUPON_PREFIX}${normalizedCode}`;

    const exists = await this.redis.exists(couponKey);
    if (!exists) {
      throw new Error('Coupon not found');
    }

    await this.redis.hset(couponKey, 'status', 'inactive');
    return { success: true, message: 'Coupon deactivated' };
  }

  /**
   * Get redemption details by ID
   */
  async getRedemption(redemptionId) {
    const redemptionKey = `${this.REDEMPTION_PREFIX}${redemptionId}`;
    const data = await this.redis.get(redemptionKey);
    return data ? JSON.parse(data) : null;
  }

  /**
   * Get user's redemption count for a specific coupon
   */
  async getUserRedemptionCount(couponCode, userId) {
    const normalizedCode = couponCode.toUpperCase().trim();
    const userRedemptionKey = `${this.USER_REDEMPTION_PREFIX}${normalizedCode}:${userId}`;
    const count = await this.redis.get(userRedemptionKey);
    return count ? parseInt(count) : 0;
  }

  /**
   * Cleanup and close connection
   */
  async close() {
    await this.redis.quit();
  }
}

